import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/db';

export async function POST(req: NextRequest) {
  try {
    const body = await req.json().catch(() => ({}));
    const name = typeof body.name === 'string' ? body.name.trim() : '';
    const token = typeof body.token === 'string' ? body.token.trim() : '';

    // Validation rules
    if (!name) {
      return NextResponse.json(
        { error: 'Display name is required.' },
        { status: 400 }
      );
    }

    if (name.length < 2 || name.length > 30) {
      return NextResponse.json(
        { error: 'Display name must be between 2 and 30 characters.' },
        { status: 400 }
      );
    }

    // Alphanumeric, spaces, underscores, hyphens only
    const nameRegex = /^[a-zA-Z0-9_\-\s]+$/;
    if (!nameRegex.test(name)) {
      return NextResponse.json(
        { error: 'Display name can only contain letters, numbers, spaces, underscores, and hyphens.' },
        { status: 400 }
      );
    }

    // Check if user already exists
    const existingUser = await prisma.user.findUnique({
      where: { name },
    });

    if (existingUser) {
      // If user exists, verify PIN (token)
      if (!token) {
        return NextResponse.json(
          {
            error: 'username_taken',
            message: 'This name is already registered. Please enter your PIN to login.',
          },
          { status: 200 } // Return 200 but indicating we need the token
        );
      }

      if (existingUser.token === token) {
        return NextResponse.json({
          id: existingUser.id,
          name: existingUser.name,
          token: existingUser.token,
          isNew: false,
        });
      } else {
        return NextResponse.json(
          { error: 'Incorrect PIN for this username. Please try again or ask a housemate to look up your PIN.' },
          { status: 401 }
        );
      }
    }

    // If user does not exist, register new user with a 6-digit PIN
    const generatedPin = Math.floor(100000 + Math.random() * 900000).toString();
    
    const newUser = await prisma.user.create({
      data: {
        name,
        token: generatedPin,
      },
    });

    return NextResponse.json(
      {
        id: newUser.id,
        name: newUser.name,
        token: newUser.token,
        isNew: true,
      },
      { status: 201 }
    );
  } catch (error) {
    console.error('Authentication API error:', error);
    return NextResponse.json(
      { error: 'An unexpected server error occurred.' },
      { status: 500 }
    );
  }
}
